class Solution(object):
    def maximizeSquareArea(self, m, n, hFences, vFences):
        MOD = 10**9 + 7
        # Add boundary fences
        hf = sorted([1] + hFences + [m])
        vf = sorted([1] + vFences + [n])

        # Compute all possible horizontal gaps
        h_gaps = set()
        for i in range(len(hf)):
            for j in range(i+1, len(hf)):
                h_gaps.add(hf[j] - hf[i])

        # Compute all possible vertical gaps and find max common gap
        ans = -1
        for i in range(len(vf)):
            for j in range(i+1, len(vf)):
                gap = vf[j] - vf[i]
                if gap in h_gaps:
                    ans = max(ans, gap)

        if ans == -1:
            return -1
        return (ans * ans) % MOD
